using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class ProductionLotsTraining : TrainingContentBase
{
    public ProductionLotsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Production Lots Overview",
            Slug = "production-lots-overview",
            Summary = "What production lots are, why traceability matters, and how lots connect to parts, jobs, purchase orders, and QC inspections.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/quality"]""",
            Tags = """["lots","traceability","quality"]""",
            ContentJson = """{"body":"## Production Lots Overview\n\nA production lot is a tracked batch of parts that share the same manufacturing conditions, material source, or receiving event. Lot tracking gives you the ability to trace every unit back to its origin — which job produced it, which purchase order supplied the raw material, which production run it came from, and which QC inspections it passed.\n\n### Why Lot Tracking Matters\n\nLot traceability is essential for:\n- **Recalls** — If a defect is discovered in a batch of parts, you need to know exactly which customers received units from that lot, which jobs used them, and where remaining stock is stored.\n- **FDA/Medical compliance** — Regulated industries (medical devices, aerospace, food-contact) require full lot traceability from raw material receipt through final shipment. QB Engineer's lot system satisfies 21 CFR Part 820 and ISO 13485 traceability requirements.\n- **Supplier accountability** — When incoming material is defective, the supplier lot number links the problem back to the vendor's batch, supporting return-to-vendor claims.\n- **Quality investigations** — QC failures can be correlated to specific lots, revealing patterns like a bad material batch or a machine that drifted out of tolerance during a particular run.\n\n### What a Lot Record Contains\n\nEach lot record captures:\n- **Lot Number** — A unique identifier, either manually assigned or auto-generated (format: `LOT-YYYYMMDD-NNN`, e.g., `LOT-20260415-001`).\n- **Part** — The part this lot is associated with. Every lot must reference exactly one part.\n- **Quantity** — How many units are in this lot.\n- **Job** (optional) — The production job that created these parts.\n- **Production Run** (optional) — The specific production run within a job.\n- **Purchase Order Line** (optional) — If the lot was received from a vendor, the PO line that sourced it.\n- **Supplier Lot Number** (optional) — The vendor's own lot/batch number for incoming material.\n- **Expiration Date** (optional) — For materials with a shelf life (adhesives, chemicals, perishable components).\n- **Notes** (optional) — Free-form notes about the lot (storage conditions, deviations, special handling).\n\n### How Lots Connect to Other Features\n\n**Parts:** Every lot is tied to a specific part number. You can query all lots for a given part to see its full production and receiving history.\n\n**Jobs:** When a job produces parts, a lot record links the output back to the job. This answers the question: 'Which job made these specific units?'\n\n**Purchase Orders:** When material arrives from a vendor, a lot record ties the received quantity to the PO line. The supplier lot number preserves the vendor's own batch identifier.\n\n**Production Runs:** Lots can be linked to specific production runs, providing finer granularity than job-level tracking.\n\n**QC Inspections:** Quality inspections reference lot numbers. The traceability query shows all inspections performed on a given lot.\n\n**Inventory (Bin Locations):** Bin contents can be tracked by lot number, so you know exactly which lot is stored in which bin.\n\n### When to Create Lots\n\n- When receiving material from a vendor (link to PO line + supplier lot number)\n- When a production run completes a batch of parts (link to job + production run)\n- When splitting or combining batches for inventory management\n- When regulated processes require batch-level documentation","sections":[]}"""
        });

        // ── Walkthrough (Article — conceptual, backend-only) ─────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Production Lots — Tracking Workflow",
            Slug = "production-lots-walkthrough",
            Summary = "A conceptual walkthrough of the lot tracking workflow: creating lots, querying traceability, and handling recalls.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/quality"]""",
            Tags = """["lots","traceability","quality","walkthrough"]""",
            ContentJson = """{"body":"## Production Lots — Tracking Workflow\n\nProduction lots are managed via the API and integrated into the Quality module. This walkthrough covers the three core workflows: creating lots, querying traceability, and handling a recall scenario.\n\n### Workflow 1: Creating a Lot on Material Receipt\n\nWhen raw material arrives from a vendor:\n\n1. **Receive the shipment** against the purchase order in the Inventory module.\n2. **A lot record is created** linking the received quantity to the PO line. The lot number is auto-generated (e.g., `LOT-20260415-001`) or you can assign a custom lot number.\n3. **Record the supplier lot number** — this is the vendor's own batch identifier printed on their packing slip or certificate of analysis.\n4. **Set an expiration date** if the material has a shelf life (adhesives, chemicals, rubber compounds).\n5. The lot is now traceable: you can look up this lot number and see which vendor supplied it, on which PO, and when it was received.\n\n### Workflow 2: Creating a Lot During Production\n\nWhen your shop produces parts:\n\n1. **A production run completes** a batch of parts on a job.\n2. **A lot record is created** linking the output to the job and production run. The quantity reflects how many good parts came off the run.\n3. **QC inspection is performed** on a sample from the lot. The inspection references the lot number.\n4. **Parts are stored** in bin locations tagged with the lot number, so inventory knows exactly which lot is in which bin.\n\n### Workflow 3: Traceability Query\n\nThe traceability query is the core of the lot system. Given a lot number, it returns the complete history:\n\n- **Part information** — which part number and description this lot represents\n- **Jobs** — all jobs that produced or consumed parts from this lot\n- **Production runs** — specific production runs linked to the lot\n- **Purchase orders** — the PO and vendor that supplied the raw material (with vendor name)\n- **Bin locations** — current inventory locations and quantities for this lot\n- **QC inspections** — all quality inspections performed on this lot, with inspector name, status, and date\n\nThis single query gives you the full chain from raw material receipt through production, inspection, storage, and shipment.\n\n### Workflow 4: Handling a Recall\n\nWhen a defect is discovered in shipped parts:\n\n1. **Identify the lot number** from the defective part's label, shipping record, or customer complaint.\n2. **Run a traceability query** on that lot number to see the full history.\n3. **Check bin locations** — are there remaining units from this lot still in inventory? If so, quarantine them.\n4. **Review QC inspections** — did the inspection catch any anomalies? Were acceptance criteria met?\n5. **Trace the supplier** — if the root cause is raw material, the supplier lot number identifies the vendor's batch. Contact the vendor with this information.\n6. **Identify affected customers** — cross-reference the lot's jobs with shipment records to find which customers received parts from this lot.\n7. **Document the investigation** — add notes to the lot record and related QC inspections.\n\n### Lot Number Format\n\nAuto-generated lot numbers follow the pattern `LOT-YYYYMMDD-NNN`:\n- `LOT` — fixed prefix\n- `YYYYMMDD` — date the lot was created\n- `NNN` — sequential counter for that day (001, 002, 003...)\n\nExample: `LOT-20260415-003` is the third lot created on April 15, 2026.\n\nCustom lot numbers are also supported — simply provide your own lot number when creating the record. This is useful when adopting a customer's or industry's lot numbering scheme.\n\n### Best Practices\n\n- **Always record supplier lot numbers** when receiving material. This is your link back to the vendor if a material issue surfaces months later.\n- **Create lots at the finest practical granularity.** One lot per production run is ideal. One lot per entire job is acceptable for low-risk parts.\n- **Set expiration dates** on any material with a shelf life. Expired lots should not be used in production.\n- **Link lots to QC inspections.** Even if your process doesn't require formal lot tracking, linking inspections to lots makes investigations dramatically faster.\n- **Use the traceability query regularly** — don't wait for a recall. Periodic traceability audits catch gaps before they matter.","sections":[]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Production Lots Field Reference",
            Slug = "production-lots-field-reference",
            Summary = "Complete reference for lot record fields, API endpoints, traceability query parameters, and validation rules.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/quality"]""",
            Tags = """["lots","traceability","quality","reference"]""",
            ContentJson = """{"title":"Production Lots Field Reference","groups":[{"heading":"Lot Record Fields","items":[{"label":"Lot Number","value":"String, max 100 characters. Auto-generated if not provided (format: LOT-YYYYMMDD-NNN, e.g., LOT-20260415-001). Can be manually assigned for custom numbering schemes."},{"label":"Part ID (required)","value":"Integer, must be greater than 0. References the part this lot is associated with. Every lot must be tied to exactly one part."},{"label":"Quantity (required)","value":"Integer, must be greater than 0. The number of units in this lot."},{"label":"Job ID (optional)","value":"Integer. References the production job that created this lot. Null for lots created from vendor receipts without a job."},{"label":"Production Run ID (optional)","value":"Integer. References the specific production run within a job. Provides finer granularity than job-level tracking."},{"label":"Purchase Order Line ID (optional)","value":"Integer. References the PO line that sourced this lot. Used when lot is created from receiving vendor material."},{"label":"Supplier Lot Number (optional)","value":"String, max 100 characters. The vendor's own batch/lot identifier. Critical for supplier accountability and recall investigations."},{"label":"Expiration Date (optional)","value":"DateTimeOffset (UTC). For materials with shelf life. Format: ISO 8601. Null for non-perishable materials."},{"label":"Notes (optional)","value":"String, max 2000 characters. Free-form notes: storage conditions, deviations, special handling instructions."},{"label":"Created At","value":"DateTimeOffset (UTC). Auto-set when the lot record is created. Used for chronological sorting."},{"label":"Created By","value":"String (User ID). Auto-set from the authenticated user. Audit trail for who created the lot."}]},{"heading":"API Endpoints","items":[{"label":"GET /api/v1/lots","value":"List lot records. Query parameters: partId (int, optional), jobId (int, optional), search (string, optional). Search matches against lot number, supplier lot number, and part number. Returns list sorted by CreatedAt descending."},{"label":"POST /api/v1/lots","value":"Create a new lot record. Request body: { partId (required), quantity (required), lotNumber (optional), jobId (optional), productionRunId (optional), purchaseOrderLineId (optional), supplierLotNumber (optional), expirationDate (optional), notes (optional) }. Returns 201 with Location header. Auto-generates lot number if not provided."},{"label":"GET /api/v1/lots/{lotNumber}/trace","value":"Traceability query. Returns the complete chain for a lot number: part info, linked jobs, production runs, purchase orders (with vendor name), bin locations (with quantities), and QC inspections (with inspector, status, date). Returns 404 if lot number not found."}]},{"heading":"Traceability Query Response","items":[{"label":"lotNumber","value":"The queried lot number."},{"label":"partNumber, partDescription","value":"The part this lot is associated with."},{"label":"jobs[]","value":"Array of { id, jobNumber, title }. All jobs linked to records with this lot number."},{"label":"productionRuns[]","value":"Array of { id, runNumber, status }. All production runs linked to this lot."},{"label":"purchaseOrders[]","value":"Array of { id, poNumber, vendorName }. Purchase orders that sourced this lot's material."},{"label":"binLocations[]","value":"Array of { locationId, locationName, quantity }. Current inventory locations holding this lot."},{"label":"inspections[]","value":"Array of { id, status, inspectorName, createdAt }. QC inspections performed on this lot."}]},{"heading":"Validation Rules","items":[{"label":"Part ID","value":"Required. Must be greater than 0. Must reference an existing part."},{"label":"Quantity","value":"Required. Must be greater than 0."},{"label":"Lot Number","value":"Optional. Max 100 characters. If omitted, auto-generated as LOT-YYYYMMDD-NNN."},{"label":"Supplier Lot Number","value":"Optional. Max 100 characters."},{"label":"Notes","value":"Optional. Max 2000 characters."},{"label":"Expiration Date","value":"Optional. Must be a valid ISO 8601 date if provided."}]},{"heading":"Authorization","items":[{"label":"Required Roles","value":"Admin, Manager, Engineer, or Production Worker. All three endpoints share the same role requirement."},{"label":"Soft Deletes","value":"Lot records use soft delete (DeletedAt timestamp). Deleted lots are excluded from queries by the global query filter."}]},{"heading":"Auto-Generated Lot Number Format","items":[{"label":"Pattern","value":"LOT-YYYYMMDD-NNN"},{"label":"Prefix","value":"LOT- (fixed)"},{"label":"Date segment","value":"YYYYMMDD — the UTC date when the lot is created (e.g., 20260415)"},{"label":"Sequence","value":"NNN — zero-padded 3-digit counter, incremented per day (001, 002, ... 999)"},{"label":"Example","value":"LOT-20260415-003 = third lot created on April 15, 2026"},{"label":"Custom override","value":"Provide your own lotNumber in the POST body to skip auto-generation. Useful for customer-mandated or industry-specific numbering."}]},{"heading":"Related Entities","items":[{"label":"Part","value":"Required FK. The part this lot tracks. Navigation: Part.PartNumber, Part.Description."},{"label":"Job","value":"Optional FK. The production job that created or consumed this lot. Navigation: Job.JobNumber, Job.Title."},{"label":"ProductionRun","value":"Optional FK. The specific production run. Navigation: ProductionRun.RunNumber, ProductionRun.Status."},{"label":"PurchaseOrderLine","value":"Optional FK. The PO line for received material. Navigation: PurchaseOrderLine.PurchaseOrder.PONumber, PurchaseOrder.Vendor.CompanyName."},{"label":"BinContent","value":"Inventory bin contents can reference lot numbers. Matched by EntityType='part', EntityId=PartId, LotNumber."},{"label":"QcInspection","value":"Quality inspections reference lot numbers via the LotNumber field. Matched directly by lot number string."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Production Lots Knowledge Check",
            Slug = "production-lots-quiz",
            Summary = "Test your knowledge of production lots: traceability, lot numbers, API usage, FDA/medical compliance, and recall workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/quality"]""",
            Tags = """["lots","traceability","quality","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pl1","text":"What is the primary purpose of production lot tracking in QB Engineer?","options":[{"id":"a","text":"To count how many parts are in inventory at any given time"},{"id":"b","text":"To trace batches of parts back to their origin for recall capability, quality investigations, and regulatory compliance","isCorrect":true},{"id":"c","text":"To schedule production runs on the shop floor"},{"id":"d","text":"To calculate the cost of goods sold for each part"}],"explanation":"Lot tracking provides full traceability from raw material receipt through production, inspection, and shipment. This is essential for recalls, FDA/medical compliance, supplier accountability, and quality investigations."},{"id":"pl2","text":"A lot record must always be linked to which of the following?","options":[{"id":"a","text":"A job and a production run"},{"id":"b","text":"A purchase order line and a supplier lot number"},{"id":"c","text":"A part — every lot must reference exactly one part","isCorrect":true},{"id":"d","text":"A QC inspection and a bin location"}],"explanation":"Part ID is the only required relationship. Every lot must be tied to exactly one part. Job, production run, purchase order line, and supplier lot number are all optional and depend on how the lot was created."},{"id":"pl3","text":"What format does QB Engineer use for auto-generated lot numbers?","options":[{"id":"a","text":"BATCH-{partNumber}-{sequence}"},{"id":"b","text":"LOT-YYYYMMDD-NNN (e.g., LOT-20260415-001)","isCorrect":true},{"id":"c","text":"LR-{year}-{globalSequence}"},{"id":"d","text":"{partNumber}-{date}-{random}"}],"explanation":"Auto-generated lot numbers follow LOT-YYYYMMDD-NNN: a fixed 'LOT-' prefix, the UTC creation date, and a zero-padded daily sequence number. Custom lot numbers can be provided to override this format."},{"id":"pl4","text":"You receive raw material from a vendor. Which fields should you populate on the lot record?","options":[{"id":"a","text":"Part ID, quantity, purchase order line ID, and supplier lot number","isCorrect":true},{"id":"b","text":"Part ID, quantity, job ID, and production run ID"},{"id":"c","text":"Part ID, quantity, and expiration date only"},{"id":"d","text":"Only lot number and quantity — the system fills in the rest"}],"explanation":"For vendor-received material, link the lot to the PO line (purchase order line ID) and record the supplier's own batch identifier (supplier lot number). Job and production run are for internally produced lots."},{"id":"pl5","text":"A customer reports a defect in parts they received. What is the first step in the recall workflow?","options":[{"id":"a","text":"Shut down all production lines immediately"},{"id":"b","text":"Identify the lot number from the part's label, shipping record, or customer complaint, then run a traceability query","isCorrect":true},{"id":"c","text":"Contact the vendor and request a replacement shipment"},{"id":"d","text":"Delete the lot record to prevent further shipments"}],"explanation":"The first step is identifying the lot number and running a traceability query. This reveals the full chain: which jobs produced it, where remaining stock is stored, which QC inspections were performed, and which supplier material was used."},{"id":"pl6","text":"What information does the traceability query (GET /api/v1/lots/{lotNumber}/trace) return?","options":[{"id":"a","text":"Only the lot record fields and the associated part number"},{"id":"b","text":"The part info, linked jobs, production runs, purchase orders with vendor names, bin locations with quantities, and QC inspections with inspector details","isCorrect":true},{"id":"c","text":"A list of all customers who received parts from this lot"},{"id":"d","text":"The financial cost breakdown of producing this lot"}],"explanation":"The traceability query returns the complete chain: part information, all linked jobs, production runs, purchase orders (with vendor name), current bin locations (with quantities), and QC inspections (with inspector name, status, and date)."},{"id":"pl7","text":"When should you set an expiration date on a lot record?","options":[{"id":"a","text":"Always — every lot must have an expiration date for compliance"},{"id":"b","text":"When the material has a shelf life, such as adhesives, chemicals, or rubber compounds","isCorrect":true},{"id":"c","text":"Only for lots received from vendors, never for internally produced lots"},{"id":"d","text":"Only when the customer specifically requests lot expiration tracking"}],"explanation":"Expiration dates are for materials with a shelf life — adhesives, chemicals, perishable components. The field is optional and should be null for non-perishable materials like metal stock or hardware."},{"id":"pl8","text":"Which roles have access to the lot management API endpoints?","options":[{"id":"a","text":"Admin and Manager only"},{"id":"b","text":"Admin, Manager, Engineer, and Production Worker","isCorrect":true},{"id":"c","text":"Admin, Manager, and Engineer — Production Workers have read-only access"},{"id":"d","text":"All roles including Office Manager and PM"}],"explanation":"The LotsController is authorized for Admin, Manager, Engineer, and Production Worker roles. All four roles can create lots and run traceability queries."},{"id":"pl9","text":"How are lot records deleted in QB Engineer?","options":[{"id":"a","text":"Hard deleted — the database row is permanently removed"},{"id":"b","text":"Soft deleted using a DeletedAt timestamp — the record is preserved but excluded from queries","isCorrect":true},{"id":"c","text":"Archived to a separate history table"},{"id":"d","text":"Lot records cannot be deleted under any circumstances"}],"explanation":"Like all entities extending BaseEntity, lot records use soft delete via the DeletedAt timestamp. The global query filter automatically excludes deleted lots from all queries, but the data is preserved for audit trail and compliance."},{"id":"pl10","text":"You want to find all lots for a specific part that were received from vendors. How do you query the API?","options":[{"id":"a","text":"GET /api/v1/lots?partId={id} — then filter results client-side for those with a purchaseOrderLineId","isCorrect":true},{"id":"b","text":"GET /api/v1/lots/{partId}/vendor-lots"},{"id":"c","text":"GET /api/v1/parts/{id}/lots?source=vendor"},{"id":"d","text":"GET /api/v1/lots/trace?partId={id}&type=received"}],"explanation":"The GET /api/v1/lots endpoint accepts a partId query parameter to filter by part. The response includes purchaseOrderLineId and supplierLotNumber fields — lots with non-null values for these were received from vendors. There is no dedicated vendor-lot endpoint."}]}"""
        });

        Log.Information("Seeded Production Lots training modules");
    }
}
